sql:
SELECT COUNT(*) AS pin_configuration_count
FROM pin_configurations
WHERE config_id = 1;

SELECT status_name
FROM pin_status
WHERE is_default = 1;

SELECT spi_flash_pin
FROM spi_flash_pins
WHERE signal_type = 'output';

SELECT config_id
FROM configurations
WHERE status = 'active';

